import React, { useEffect, useState } from 'react'
import * as _Util from '../store/Util';
import { getSectionByGtoken, updFsObjByColl, updObserveChanges } from '../actions/common'
import { useSelector,useDispatch } from 'react-redux'
import { selectObserveChanges, setObserveLogin } from '../store/qvamarketsSlice';




const LoginComponent = (props) => {  
  const [initialize, setInitialize] = useState(false);
  const observeChanges =  useSelector(selectObserveChanges);
  const dispatch = useDispatch();  

  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      _Util.initGapi(()=>renderBtn());

    }
  })



  /*********************************************************************************************************************************************/  
  /**************************************   renderBtn load auht function and render google singin button ****************************************/
  /*********************************************************************************************************************************************/
  


  const renderBtn = () => {
    let _gapi = window.gapi;
    _gapi.load('auth2', function() {
      setTimeout(()=>{
        _gapi.signin2.render('google-signin-button', {
          width: 232,
          height: 40,
          longtitle: true,
          hidden:true,
          onsuccess: onSuccess,
          onfailure: onFail,
        });
        setTimeout(()=>{
          onSuccess();
        },350)
      },350)
    });
  }

  const onFail = (e) => {
    console.log("onFail",e)
    onSuccess();
  }


  const onSuccess = (e) => {
    handleUser();
    setTimeout(()=>handleUser(),2650)
  }


  
  const handleUser = (e) => {
    let _gapi = window.gapi;
    let cu = _gapi.auth2.getAuthInstance();
    let currentUser = cu && cu.currentUser.get();    
    let itm = null
    var gProfile = cu && cu.currentUser.get().getBasicProfile();
    let openID = currentUser && currentUser["Ba"];  
    if (gProfile) {
      itm = {}
      itm["name"]   = gProfile.getName();
      itm["email"]  = gProfile.getEmail();
      itm["picture"] = gProfile.getImageUrl();
      openID = gProfile.getId();
      itm["id"] = openID;
    }
    console.log("openID for this site - ",openID);
    if(_Util.getStore('userFs')){
      if(_Util.getStore('userFs')[openID]){
        let usPr = _Util.getStore('userFs')[openID];
        usPr["id"] = openID;
        usPr["isSpaOwner"] && _Util.updStore('isSpaOwner',usPr["isSpaOwner"]);
        _Util.updStore('userProfile',usPr);
        _Util.updStore("singinView", false);
        _Util.updStore('isSpaOwner', usPr && usPr.isSpaOwner);
        dispatch(setObserveLogin());
      }
      else if(itm){
        updFsObjByColl("users", openID, itm);
        _Util.updStore('userProfile',itm);
        dispatch(setObserveLogin());
      }
    }
    else{
      if(itm && itm.id){
        updFsObjByColl("users", openID, itm);
        _Util.updStore('userProfile',itm);
        dispatch(setObserveLogin());
      }
    }
  }




  return (
    <>
    <style>
      {`
      
        .jessie_nails
        #google-signin-button{
          background-color: #fef6f9;
        }

        .jessie_nails
        .btnWrapp{
          position: relative
        }


        .jessie_nails
        .btnWrapp
        .mask{
          background-color: #fef6f9;
          position: absolute
        }
      
      `}
    </style>
    {initialize?
      <div id="g_signin2_bx jessie_nails" >
        <div className="login_message" >
          <img src={"https://firebasestorage.googleapis.com/v0/b/hrm-1128.appspot.com/o/jessie_nails%2Fjessie_nail.webp?alt=media&token=faa2f7ff-0c01-4d07-b4c8-0bbd1f317df3"} alt="Jessie"/>
          <p>
            {_Util.translatetext(220)}
          </p>
          <div className="_dsplFlx">
            <div className="flexSpace"></div>
            <div className='btnWrapp' >
              <div id="google-signin-button" data-theme="dark"  >
              
              </div>
              <div className="mask">

              </div>
            </div>
          </div>
        </div>
      </div>
    :null}
    </>
  )
}


export default LoginComponent

